create table statistics
(
    id              bigint auto_increment comment '主键ID'
        primary key,
    statistics_type varchar(50)                        not null comment '统计类型: user_register(用户注册), api_request(接口请求)',
    api_type        varchar(50)                        null comment '接口类型: learning(学习助手), love(恋爱智能体), shopping(购物助手), xiaozhi(硅谷小智)',
    statistics_date datetime                           not null comment '统计日期',
    count           int      default 1                 not null comment '统计数值',
    create_time     datetime default CURRENT_TIMESTAMP not null comment '创建时间',
    update_time     datetime default CURRENT_TIMESTAMP not null on update CURRENT_TIMESTAMP comment '更新时间'
)
    comment '统计数据表' collate = utf8mb4_unicode_ci;

create index idx_api_type
    on statistics (api_type);

create index idx_create_time
    on statistics (create_time);

create index idx_statistics_date
    on statistics (statistics_date);

create index idx_statistics_type
    on statistics (statistics_type);
